/** Which line-art set to render for a character. */
export type CharacterVariant = 'base' | 'pilot'

export function hasCharacterArt(id: string): boolean {
  return id in ART
}

interface CharacterArtProps {
  id: string
  size?: number
  /** 'pilot' shows the aviator-costume variant used when a session is on autopilot. */
  variant?: CharacterVariant
}

/** Renders a character's line-art face; null when no art exists for the id. */
export function CharacterArt({ id, size = 26, variant = 'base' }: CharacterArtProps): JSX.Element | null {
  // Pilot art is traced in a 512 coordinate space; the base set uses 1024.
  const pilot = variant === 'pilot' && id in ART_PILOT
  const art = pilot ? ART_PILOT[id] : ART[id]
  if (!art) return null
  return (
    <svg
      className="character__art"
      viewBox={pilot ? '0 0 512 512' : '0 0 1024 1024'}
      width={size}
      height={size}
      fill="currentColor"
      stroke="none"
      aria-hidden="true"
      focusable="false"
    >
      {art}
    </svg>
  )
}
